#include<bits/stdc++.h>
using namespace std;
int nxt[100010],ans[100010];
int step[100010],huan[100010];
int color[100010];
void dfs1(int x,int huan1)
{
	if(huan1==huan[x])
	{
		return;
	}
	huan[x]=huan1;
	dfs1(nxt[x],huan1);
}
int dfs(int x,int step1,int color1)
{
	if(color[x]!=0)
	{
		if(color[x]==color1)
		{
			huan[x]=step1-step[x];
			int k=nxt[x];
			dfs1(k,huan[x]);
		}
		return huan[x];
	}
	color[x]=color1;
	step[x]=step1;
	int nxt1=dfs(nxt[x],step1+1,color1);
	if(huan[x]==0)
	{
		huan[x]=nxt1+1;
	}
	return huan[x];
}
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&nxt[i]);
	}
	for(int i=1;i<=n;i++)
	{
		if(color[i]==0)
		{
			dfs(i,1,i);
		}
	}
	for(int i=1;i<=n;i++)
	{
		printf("%d\n",huan[i]);
	}
	return 0;
}
